default(48) // Default 48h SLA for bottleneck\n\n  tenant           Tenant           @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  pipelineTemplate PipelineTemplate @relation(fields: [pipelineTemplateId], references: [id], onDelete: Cascade)\n  candidates       Candidate[]\n  evaluations      Evaluation[]\n\n  @@unique([pipelineTemplateId, orderIndex])\n}\n\nmodel Candidate {\n  id             String   @id @default(uuid())\n  tenantId       String\n  pipelineId     String\n  currentStageId String?\n  firstName      String\n  lastName       String\n  email          String\n  status         String   @default(\"ACTIVE\") // ACTIVE, REJECTED, HIRED, ON_HOLD\n  stageEnteredAt DateTime @default(now())\n  version        Int      @default(1) // OCC support\n\n  tenant       Tenant           @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  pipeline     PipelineTemplate @relation(fields: [pipelineId], references: [id], onDelete: Restrict)\n  currentStage PipelineStage?   @relation(fields: [currentStageId], references: [id], onDelete: SetNull)\n  evaluations  Evaluation[]\n  decisions    Decision[]\n  slaAlerts    SlaAlert[]\n\n  @@index([tenantId, pipelineId, currentStageId])\n}\n\nmodel Evaluation {\n  id             String   @id @default(uuid())\n  tenantId       String\n  candidateId    String\n  stageId        String\n  interviewerId  String\n  scores         Json // Flexible scorecard (JSONB)\n  recommendation String // 'STRONG_HIRE', 'HIRE', 'NO_HIRE'\n  createdAt      DateTime @default(now())\n\n  tenant      Tenant        @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  candidate   Candidate     @relation(fields: [candidateId], references: [id], onDelete: Cascade)\n  stage       PipelineStage @relation(fields: [stageId], references: [id], onDelete: SetNull)\n  interviewer User          @relation(fields: [interviewerId], references: [id], onDelete: Restrict)\n}\n\nmodel Decision {\n  id            String   @id @default(uuid())\n  tenantId      String\n  candidateId   String\n  finalDecision String // 'HIRE', 'NO_HIRE'\n  hasConflict   Boolean  @default(false)\n  decisionNotes String?\n  createdAt     DateTime @default(now())\n\n  tenant    Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  candidate Candidate @relation(fields: [candidateId], references: [id], onDelete: Cascade)\n}\n\nmodel SlaAlert {\n  id           String   @id @default(uuid())\n  tenantId     String\n  candidateId  String\n  stageId      String\n  alertMessage String\n  isResolved   Boolean  @default(false)\n  createdAt    DateTime @default(now())\n\n  tenant    Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  candidate Candidate @relation(fields: [candidateId], references: [id], onDelete: Cascade)\n}\n",
